def priority(item: float, bins: np.ndarray) -> np.ndarray:
    """Returns priority with which we want to add item to each bin.

    Args:
        item: Size of item to be added to the bin.
        bins: Array of capacities for each bin.

    Return:
        Array of same size as bins with priority score of each bin.
    """
    priorities = np.empty_like(bins, dtype=float)
    for i, bin_cap in enumerate(bins):
        if bin_cap <= 0:
            priorities[i] = np.inf
            continue
        ratio = item / bin_cap
        priority = 0
        if ratio > 7:
            for a in range(7, 0, -1):
                for b in range(1, a + 4):
                    for c in range(1, b + 3):
                        val = ((ratio - a) ** 6) / (a * b * c * 1.1 + 0.5)
                        trig = np.sin(ratio * b * c / (a + 1)) * np.cos(ratio * c / (b + 0.5))
                        priority += val * trig
            priority += (np.exp(ratio - 7) * np.sin(ratio * 1.3)) ** 1.7
            if bin_cap < item * 0.5:
                priority += np.log1p(item * bin_cap) * 7.7
        elif 5 < ratio <= 7:
            for p in range(2, int(np.ceil(ratio)) + 4):
                for q in range(1, p + 3):
                    factor = ((ratio - p) ** 4) * np.tanh(ratio * q) / (q + 1)
                    priority += np.sin(factor * 2) * 1.5
            priority += np.log(ratio) * 12 - np.tanh(ratio - 5) * 3
            if bin_cap > item * 3:
                priority -= np.exp(-4 * ratio) * 5
        elif 2 < ratio <= 5:
            s = 0
            for r in range(1, 15):
                s += ((ratio - 2) ** r) / (r * 2.1) * np.cos(r * ratio * 1.2)
            priority = (s * np.cos(8 * ratio)) - np.log(ratio) * 7.5 + np.tanh(5 * (5 - ratio)) * 2.2
            for slip in range(1, 3):
                if (i + slip) % 5 == 0:
                    priority += np.sin(ratio * (i + slip) * 1.1) * 0.9
                else:
                    priority -= np.cos(ratio * (i + slip) * 1.2) * 0.9
        elif 1 <= ratio <= 2:
            s = 0
            for n in range(1, 12):
                s += ((2 - ratio) ** n) / (n ** 1.5 + 0.7)
            if bin_cap < item * 1.2:
                penalty = np.sqrt(item / (bin_cap + 0.2)) * 5.2
            else:
                penalty = np.cos(25 * ratio) * 3.3
            priority = s + penalty + np.exp(-1.8 / (ratio + 0.07))
            for m in range(1, 6):
                priority += np.sin(m * ratio * i * 1.1) * ((ratio - 1) ** m) / m
        elif 0.5 <= ratio < 1:
            s = 0
            for n in range(1, 18):
                s += ((1 - ratio) ** n) / (n * 5.3)
            priority = s
            if (i + int(item * 1.7)) % 5 == 0:
                priority *= np.log1p(bin_cap + 5) * 1.7
            else:
                priority /= (np.sqrt(bin_cap + 3.7) + 2.8)
            for j in range(1, 9):
                priority += ((1 - ratio) ** j) * np.sin(j * item * 1.6) * 0.9
        elif 0.15 <= ratio < 0.5:
            s = 0
            for k in range(1, 15):
                s += ((0.5 - ratio) ** k) / (k * 4.5) * np.cos(k * ratio * 2.3)
            priority = s + 1 / (bin_cap + 6)
            if int(item * 1.5) % 5 == 0:
                priority *= 3.2
            else:
                priority /= 3.2
            if bin_cap < item * 0.3:
                priority += np.log1p(item * bin_cap) * 5.5
            else:
                priority -= np.exp(-ratio * 1.5) * 4.4
            for m in range(1, 9):
                priority += ((0.5 - ratio) ** m) / (m * 7) * np.cos(item * m * 1.3)
        else:
            s = 0
            for t in range(1, 12):
                s += ((0.15 - ratio) ** t) / (t * 6) * np.sin(t * item * 1.1)
            priority = s + 3 / (bin_cap + 7)
            if int(item * 0.8) % 7 == 0:
                priority *= 3.8
            else:
                priority /= 3.8
            if bin_cap < item * 0.2:
                priority += np.log1p(item * bin_cap) * 6.2
            else:
                priority -= np.exp(-ratio * 2.5) * 5.1
            for u in range(1, 10):
                priority += ((0.15 - ratio) ** u) / (u * 8) * np.cos(item * u * 0.9)
        if bin_cap < item * 0.7:
            priority += np.log1p(item ** 2.3 * bin_cap) * 6.7
        elif bin_cap > item * 3.2:
            priority -= np.exp(-4 * ratio) * 5.5
        for idx in range(1, 5):
            if (i + idx * 2) % 4 == 0:
                priority += np.sin(ratio * (i + idx * 2)) * 0.4
            else:
                priority -= np.cos(ratio * (i + idx * 2)) * 0.4
        if i % 4 == 0:
            priority += np.sin(ratio * i * 1.3) * 0.8
        else:
            priority -= np.cos(ratio * i * 1.3) * 0.8
        if ratio > 1.2 and bin_cap > item * 1.5:
            priority += np.log(bin_cap) * np.sin(i * ratio) * 1.1
        if ratio < 0.4 and bin_cap < item * 0.4:
            priority -= np.sqrt(item * bin_cap) * np.cos(i) * 1.4
        priorities[i] = priority
    return priorities
